class ABACPolicy:
    def __init__(self):
        self.policies = []

    def add_policy(self, name, conditions):
        self.policies.append({'name': name, 'conditions': conditions})

    def evaluate(self, subject, resource, action, environment):
        for policy in self.policies:
            if self._check_conditions(policy['conditions'], 
                                      subject, resource, action, environment):
                return 'PERMIT'
        return 'DENY'

    def _check_conditions(self, conditions, sub, res, act, env):
        for cond in conditions:
            attr_type = cond['attribute']
            operator = cond['operator']
            value = cond['value']

            if attr_type == 'subject':
                actual = sub.get(cond['name'])
            elif attr_type == 'resource':
                actual = res.get(cond['name'])
            elif attr_type == 'action':
                actual = act.get(cond['name'])
            elif attr_type == 'environment':
                actual = env.get(cond['name'])

            if not self._compare(actual, operator, value):
                return False
        return True

    def _compare(self, actual, operator, expected):
        if operator == '==':
            return actual == expected
        elif operator == '!=':
            return actual != expected
        elif operator == '>=':
            return actual >= expected
        elif operator == '<=':
            return actual <= expected
        elif operator == 'contains':
            return expected in actual
        return False

