import java.util.*;

public class ABACPDP {
    private List<Policy> policies;

    public ABACPDP() {
        this.policies = new ArrayList<>();
    }

    public void addPolicy(Policy policy) {
        policies.add(policy);
    }

    public String evaluate(AccessRequest request) {
        for (Policy policy : policies) {
            if (evaluatePolicy(request, policy)) {
                return "PERMIT";
            }
        }
        return "DENY";
    }

    private boolean evaluatePolicy(AccessRequest request, Policy policy) {
        for (Condition condition : policy.getConditions()) {
            Object attributeValue = getAttributeValue(request, condition.getAttributeName());
            if (!compareValues(attributeValue, condition.getOperator(), condition.getExpectedValue())) {
                return false;
            }
        }
        return true;
    }

    private Object getAttributeValue(AccessRequest request, String attrName) {
        Map<String, Object> allAttrs = new HashMap<>();
        allAttrs.putAll(request.getSubjectAttributes());
        allAttrs.putAll(request.getResourceAttributes());
        allAttrs.putAll(request.getActionAttributes());
        allAttrs.putAll(request.getEnvironmentAttributes());
        return allAttrs.get(attrName);
    }

    private boolean compareValues(Object actual, String operator, Object expected) {
        switch (operator) {
            case "==": return actual.equals(expected);
            case "!=": return !actual.equals(expected);
            case ">=": return ((Comparable)actual).compareTo(expected) >= 0;
            case "<=": return ((Comparable)actual).compareTo(expected) <= 0;
            default: return false;
        }
    }
}

